import React from "react"
import { FormattedMessage, injectIntl } from "gatsby-plugin-intl"
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome"
import SEO from "../components/seo";
import { buildICSEntry } from "../js/custom"
import Poster from "../images/Farai_Poster.jpg"

const Shows = ({intl}) => {
    class ShowLocation {
        constructor(name, link) {
            this._name = name;
            this._link = link;
        }

        get name() {
            return this._name;
        }

        set name(value) {
            this._name = value;
        }

        get link() {
            return this._link;
        }

        set link(value) {
            this._link = value;
        }
    }

    class Show {
        /**
         * @param dateExport : string
         * @param timeStart : string
         * @param timeEnd : string
         * @param location : ShowLocation
         * @param cancelled : boolean
         * @param cancelReason : string
         */
        constructor(dateExport, timeStart, timeEnd, location, cancelled = false, cancelReason = "", privateEvent = false) {
            this._dateExport = dateExport;
            this._timeStart = timeStart;
            this._timeEnd = timeEnd;
            this._location = location;
            this._cancelled = cancelled;
            this._cancelReason = cancelReason;
            this._location = location;
            this._private = privateEvent;
        }

        get private() {
            return this._private;
        }

        set private(value) {
            this._private = value;
        }

        get dateExport() {
            return this._dateExport;
        }

        set dateExport(value) {
            this._dateExport = value;
        }

        get timeStart() {
            return this._timeStart;
        }

        set timeStart(value) {
            this._timeStart = value;
        }

        get timeEnd() {
            return this._timeEnd;
        }

        set timeEnd(value) {
            this._timeEnd = value;
        }

        get location() {
            return this._location;
        }

        set location(value) {
            this._location = value;
        }

        get cancelled() {
            return this._cancelled;
        }

        set cancelled(value) {
            this._cancelled = value;
        }

        get cancelReason() {
            return this._cancelReason;
        }

        /**
         * @param {string} value
         */
        set cancelReason(value) {
            this._cancelReason = value;
        }
    }

    const funambules = new ShowLocation(
        "Funambules (Lübeck)",
        "https://goo.gl/maps/WfQcn4m7ChYrtskk6"
    );
    const klangbar = new ShowLocation(
        "Klangbar (Bergedorf)",
        "https://g.page/Suhrhof"
    );
    const bad_oldesloe_stadtfest = new ShowLocation(
        "Stadtfest (Bad Oldesloe)",
        "https://goo.gl/maps/NfCabkot524pYYDJ6"
    );
    const fehmarn_stadtfest = new ShowLocation(
        "Stadtfest (Fehmarn)",
        "https://goo.gl/maps/eKaV1T1QbbJY77148"
    );
    const st_peter_ording_drachenfest = new ShowLocation(
        "Drachenfestival (St.‑Peter‑Ording)", //These are special non breaking hyphens
        "https://goo.gl/maps/YiT6mvDtnL86MaPP6"
    );
    const scharbeuz = new ShowLocation(
        intl.formatMessage({id: "private_event"}) + " (Scharbeuz)",
        ""
    );
    const private_event = new ShowLocation(
        intl.formatMessage({id: "private_event"}),
        ""
    );
    const timeRegex = /^\d{2,}:\d{2}$/; //e.g. 00:00
// for filtering out past shows
    let today = new Date();
    today.setHours(0, 0, 0, 0);

    const dateFormatOptions = {weekday: 'short', year: 'numeric', month: 'short', day: '2-digit'};
    // date format: Month/Day/Year
    const shows = [
        new Show(
            "8/13/2021",
            "",
            "",
            private_event,
            false,
            "",
            true
        ),
        // new Show(
        //     "8/2/2020",
        //     "",
        //     "",
        //     private_event,
        //     true,
        //     "cancelled_corona",
        //     true
        // ),
        // new Show(
        //     "6/6/2020",
        //     "20:15",
        //     "22:15",
        //     bad_oldesloe_stadtfest,
        //     true,
        //     "cancelled_corona"
        // ),
        // new Show(
        //     "6/20/2020",
        //     "20:30",
        //     "23:00",
        //     funambules,
        //     true,
        //     "cancelled_corona"
        // ),
        // new Show(
        //     "7/5/2020",
        //     "14:00",
        //     "16:00",
        //     fehmarn_stadtfest,
        //     true,
        //     "cancelled_corona"
        // ),
        // new Show(
        //     "8/8/2020",
        //     "ca. 12:00",
        //     "",
        //     st_peter_ording_drachenfest,
        //     true,
        //     "cancelled_corona"
        // ),
        // new Show(
        //     "8/14/2020",
        //     "20:00",
        //     "22:00",
        //     klangbar,
        //     true
        // ),
        // new Show(
        //     "8/23/2020",
        //     "",
        //     "",
        //     scharbeuz,
        //     true,
        //     "",
        //     true
        // ),
        // new Show(
        //     "10/2/2020",
        //     "19:00",
        //     "23:00",
        //     funambules,
        //     false
        // ),
    ];
    return (
        <>
            <SEO title="Shows"/>
            <div className="pb-3">
                <h3>Upcoming Shows</h3>
                <FormattedMessage id="shows_text"/>
            </div>
            <div className="container">
                <div className="row">
                    <div className="col-md order-2">
                        <img src={Poster} className="img-fluid oneness-poster rounded-lg float-right"
                             alt="Oneness Live Poster"/>
                    </div>
                    <div className="col-md order-1 order-md-3">
                        <table className="table table-dark table-hover text-left">
                            <thead>
                            <tr>
                                <th scope="col" className="text-center">
                                    <FontAwesomeIcon icon="calendar-alt"/>
                                </th>
                                <th scope="col">
                                    <FormattedMessage id="shows_table_when"/>
                                </th>
                                <th scope="col">
                                    <FormattedMessage id="shows_table_where"/>
                                </th>
                            </tr>
                            </thead>
                            <tbody>
                            {shows.filter(show => new Date(Date.parse(show.dateExport)) >= today)
                                .sort((a, b) => {
                                    return new Date(Date.parse(a.dateExport)) - new Date(Date.parse(b.dateExport));
                                }).map(show => (
                                    <tr key={show.dateExport} className={show.cancelled ? "bg-danger" : ""}>
                                        <th scope="row">
                                            {
                                                (!show.cancelled && !show.private) &&
                                                <button className="btn btn-sm btn-primary"
                                                        title={intl.formatMessage({id: "shows_table_download"})}
                                                        onClick={() => {
                                                            buildICSEntry(
                                                                `${show.dateExport} ${timeRegex.test(show.timeStart) ? show.timeStart : "08:00"}`,
                                                                `${show.dateExport} ${timeRegex.test(show.timeEnd) ? show.timeEnd : "18:00"}`,
                                                                show.location.name
                                                            )
                                                        }}>
                                                    <FontAwesomeIcon icon="file-download"/>
                                                </button>
                                            }
                                        </th>
                                        <td className="align-middle">
                                            {
                                                show.cancelled &&
                                                <p className="small m-0">
                                                    {intl.formatMessage({id: "cancelled"}) + (show.cancelReason ? intl.formatMessage({id: show.cancelReason}) : "")}
                                                </p>
                                            }
                                            <p className="small m-0"
                                               style={{textDecorationLine: show.cancelled ? 'line-through' : 'initial'}}>
                                                {new Date(Date.parse(show.dateExport)).toLocaleDateString(intl.locale, dateFormatOptions)}
                                                {show.timeStart && <span>, {show.timeStart} <FontAwesomeIcon icon="clock"/></span>}
                                            </p>
                                        </td>
                                        <td className="align-middle">
                                            {(show.cancelled || show.private) ?
                                                <div target="_blank" rel="noopener noreferrer" href={show.location.link}
                                                     className={(show.cancelled ? "oneness-strikethrough" : "")}>
                                                    <FontAwesomeIcon icon="map-marker-alt"/> {show.location.name}
                                                </div>
                                                :
                                                <a target="_blank" rel="noopener noreferrer" href={show.location.link}>
                                                    <FontAwesomeIcon icon="map-marker-alt"/> {show.location.name}
                                                </a>
                                            }
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </>
    )
};

export default injectIntl(Shows)
