import $ from 'jquery'
import icsFormatter from "./ics.min"

// timeUpdate
// Synchronizes play position with current point in audio
function timeUpdate(event) {
    var music = event.currentTarget;
    var duration = music.duration;
    if (music.currentTime === duration) {
        var button = $('#music-btn-' + music.id.slice(music.id.length - 2))[0];
        button.className = "";
        button.className = "fas fa-play-circle";
    }
}

//Play and Pause
export function toggleMusic(button) {
    var icon = button.children[0];
    var number = icon.id.slice(icon.id.length - 2);
    var parsedNo = parseInt(number);
    var music = $('#music' + number)[0];
    //Turn other off
    for (var i = 1; i < 5; i++) {
        if (i !== parsedNo) {
            var otherMusic = $('#music0' + i)[0];
            otherMusic.pause();
            // var otherIcon = $('#music-btn-0' + i)[0];
            // otherIcon.className = "";
            // otherIcon.className = "fas fa-play-circle";
        }
    }
    // Toggle clicked music
    // start music
    if (music.paused && i) {
        music.play();
        music.addEventListener("timeupdate", timeUpdate, false);
        // remove play, add pause
        // icon.className = "";
        // icon.className = "fas fa-pause-circle";
    } else { // pause music
        music.pause();
        // remove pause, add play
        // icon.className = "";
        // icon.className = "fas fa-play-circle";
    }
}

export function buildICSEntry(beg, endStr, place) {

    var calEntry = icsFormatter();

    // var title = 'Event Title';
    var title = 'Oneness - Live';
    var begin = new Date(beg);
    var end = new Date(endStr);
    // var description = 'This is the description...';
    var description = '';
    // var place = 'Deutschland';

    calEntry.addEvent(title, description, place, begin.toUTCString(), end.toUTCString());
    calEntry.download('Oneness (Live)');
}

